sql:
SELECT origin_node_id, destination_node_id 
FROM migration_records 
WHERE number_of_migrants > 1000;

SELECT COUNT(*)
FROM migration_records
WHERE origin_node_id = 1;

SELECT migration_id 
FROM migration_records
WHERE number_of_migrants > (
    SELECT AVG(number_of_migrants) 
    FROM migration_records
);

SELECT country_code
FROM migration_records
WHERE migration_id = 1;
